     1→import { v4 as uuidv4 } from 'uuid';
     2→import * as pty from 'node-pty';
     3→import * as fs from 'fs/promises';
     4→import * as path from 'path';
     5→import { EventEmitter } from 'events';
     6→import type { Session } from '../types/index.js';
     7→
     8→export class SessionManager extends EventEmitter {
     9→  private sessions: Map<string, Session> = new Map();
    10→  private workspacesDir = path.join(process.cwd(), 'workspaces');
    11→
    12→  async createSession(options: { name?: string } = {}): Promise<Session> {
    13→    const id = uuidv4();
    14→    const name = options.name || `session-${id.slice(0, 8)}`;
    15→    const workDir = path.join(this.workspacesDir, id);
    16→
    17→    // Create workspace directory
    18→    await fs.mkdir(workDir, { recursive: true });
    19→
    20→    // Spawn Claude Code CLI
    21→    const cliProcess = this.spawnClaudeCode(id, workDir);
    22→
    23→    const session: Session = {
    24→      id,
    25→      name,
    26→      status: 'starting',
    27→      workingDirectory: workDir,
    28→      cliProcess,
    29→      createdAt: new Date(),
    30→      lastActivity: new Date(),
    31→      commandsExecuted: 0
    32→    };
    33→
    34→    this.sessions.set(id, session);
    35→
    36→    // Wait for CLI to be ready
    37→    cliProcess.onData((data: string) => {
    38→      if (data.includes('Enter a command') || data.includes('How can I help')) {
    39→        session.status = 'ready';
    40→        this.emit('session:ready', session);
    41→      }
    42→      // Emit all output for dashboard
    43→      this.emit('session:output', { sessionId: id, data });
    44→    });
    45→
    46→    this.emit('session:created', session);
    47→    return session;
    48→  }
    49→
    50→  private spawnClaudeCode(sessionId: string, workDir: string) {
    51→    const cli = pty.spawn('claude', ['-p', '--output-format', 'json'], {
    52→      name: 'xterm-color',
    53→      cols: 80,
    54→      rows: 24,
    55→      cwd: workDir,
    56→      env: {
    57→        ...process.env,
    58→        CLAUDE_SESSION_ID: sessionId,
    59→        CLAUDE_HOOKS_ENABLED: 'true'
    60→      }
    61→    });
    62→
    63→    cli.onExit(({ exitCode }) => {
    64→      const session = this.sessions.get(sessionId);
    65→      if (session) {
    66→        session.status = 'terminated';
    67→        this.emit('session:terminated', { sessionId, exitCode });
    68→      }
    69→    });
    70→
    71→    return cli;
    72→  }
    73→
    74→  sendCommand(sessionId: string, command: string): void {
    75→    const session = this.sessions.get(sessionId);
    76→    if (!session || session.status === 'terminated') {
    77→      throw new Error(`Session ${sessionId} not found or terminated`);
    78→    }
    79→
    80→    session.cliProcess?.write(command + '\n');
    81→    session.status = 'busy';
    82→    session.lastActivity = new Date();
    83→    session.commandsExecuted++;
    84→
    85→    this.emit('session:busy', session);
    86→  }
    87→
    88→  terminateSession(sessionId: string): void {
    89→    const session = this.sessions.get(sessionId);
    90→    if (!session) return;
    91→
    92→    session.cliProcess?.kill();
    93→    session.status = 'terminated';
    94→    this.emit('session:terminated', { sessionId });
    95→  }
    96→
    97→  getSession(sessionId: string): Session | undefined {
    98→    return this.sessions.get(sessionId);
    99→  }
   100→
   101→  getAllSessions(): Session[] {
   102→    return Array.from(this.sessions.values());
   103→  }
   104→
   105→  handleHookEvent(event: any): void {
   106→    const session = this.sessions.get(event.session_id);
   107→    if (!session) return;
   108→
   109→    this.emit('session:hook', { sessionId: event.session_id, event });
   110→
   111→    // Update status based on hook
   112→    if (event.hook_event_name === 'Stop' && session.status === 'busy') {
   113→      session.status = 'ready';
   114→      this.emit('session:ready', session);
   115→    }
   116→  }
   117→}
