     5→export function setupDashboardSocket(wss: WebSocketServer, sessionManager: SessionManager) {
     6→  // Forward session events to all dashboard clients
     7→  sessionManager.on('session:created', (session: Session) => {
     8→    broadcast({ type: 'session:created', session });
     9→  });
    10→
    11→  sessionManager.on('session:ready', (session: Session) => {
    12→    broadcast({ type: 'session:updated', session });
    13→  });
    14→
    15→  sessionManager.on('session:busy', (session: Session) => {
    16→    broadcast({ type: 'session:updated', session });
    17→  });
    18→
    19→  sessionManager.on('session:terminated', (data: { sessionId: string }) => {
    20→    broadcast({ type: 'session:terminated', sessionId: data.sessionId });
    21→  });
    22→
    23→  sessionManager.on('session:output', (data: { sessionId: string; data: string }) => {
    24→    broadcast({ type: 'session:output', sessionId: data.sessionId, data: data.data });
    25→  });
    26→
    27→  sessionManager.on('session:hook', (data: { sessionId: string; event: any }) => {
    28→    broadcast({ type: 'session:hook', sessionId: data.sessionId, event: data.event });
    29→  });
    30→
    31→  wss.on('connection', (ws) => {
    32→    console.log('Dashboard client connected');
    33→
    34→    // Send current sessions on connect
    35→    ws.send(JSON.stringify({
    36→      type: 'init',
    37→      sessions: sessionManager.getAllSessions()
    38→    }));
    39→
    40→    ws.on('message', (data) => {
    41→      try {
    42→        const msg = JSON.parse(data.toString());
    43→        handleClientMessage(ws, msg, sessionManager);
    44→      } catch (err) {
    45→        console.error('Invalid message:', err);
    46→      }
    47→    });
    48→
    49→    ws.on('close', () => {
    50→      console.log('Dashboard client disconnected');
    51→    });
    52→  });
    53→
    54→  function broadcast(message: any) {
    55→    wss.clients.forEach((client) => {
    56→      if (client.readyState === 1) { // OPEN
    57→        client.send(JSON.stringify(message));
    58→      }
    59→    });
    60→  }
    61→
    62→  function handleClientMessage(ws: any, msg: any, sessionManager: SessionManager) {
    63→    switch (msg.type) {
    64→      case 'subscribe':
    65→        // Handle session-specific subscriptions
    66→        break;
    67→      case 'command':
    68→        sessionManager.sendCommand(msg.sessionId, msg.command);
    69→        break;
    70→      case 'terminate':
    71→        sessionManager.terminateSession(msg.sessionId);
    72→        break;
    73→    }
    74→  }
    75→}
    76→

