    13→function App() {
    14→  const [sessions, setSessions] = useState<Session[]>([]);
    15→  const [selectedSession, setSelectedSession] = useState<Session | null>(null);
    16→  const [output, setOutput] = useState<string[]>([]);
    17→  const [wsConnected, setWsConnected] = useState(false);
    18→
    19→  useEffect(() => {
    20→    const ws = io('http://localhost:3000');
    21→
    22→    ws.on('connect', () => {
    23→      console.log('Connected to dashboard');
    24→      setWsConnected(true);
    25→    });
    26→
    27→    ws.on('disconnect', () => {
    28→      setWsConnected(false);
    29→    });
    30→
    31→    ws.on('init', (data: { sessions: Session[] }) => {
    32→      setSessions(data.sessions);
    33→    });
    34→
    35→    ws.on('session:created', (data: { session: Session }) => {
    36→      setSessions(prev => [...prev, data.session]);
    37→    });
    38→
    39→    ws.on('session:updated', (data: { session: Session }) => {
    40→      setSessions(prev => prev.map(s => s.id === data.session.id ? data.session : s));
    41→    });
    42→
    43→    ws.on('session:output', (data: { sessionId: string; data: string }) => {
    44→      if (selectedSession && data.sessionId === selectedSession.id) {
    45→        setOutput(prev => [...prev, data.data]);
    46→      }
    47→    });
    48→
    49→    ws.on('session:terminated', (data: { sessionId: string }) => {
    50→      setSessions(prev => prev.filter(s => s.id !== data.sessionId));
    51→      if (selectedSession?.id === data.sessionId) {
    52→        setSelectedSession(null);
    53→        setOutput([]);
    54→      }
    55→    });
    56→
    57→    return () => {
    58→      ws.disconnect();
    59→    };
    60→  }, [selectedSession]);
    61→
    62→  const createSession = async () => {
    63→    await fetch('http://localhost:3000/api/session', {
    64→      method: 'POST',
    65→      headers: { 'Content-Type': 'application/json' },
    66→      body: JSON.stringify({})
    67→    });
    68→  };
    69→
    70→  const terminateSession = async (id: string) => {
    71→    await fetch(`http://localhost:3000/api/session/${id}`, {
    72→      method: 'DELETE'
    73→    });
    74→  };
    75→
    76→  const sendCommand = async (command: string) => {
    77→    if (!selectedSession) return;
    78→    await fetch(`http://localhost:3000/api/session/${selectedSession.id}/command`, {
    79→      method: 'POST',
    80→      headers: { 'Content-Type': 'application/json' },
    81→      body: JSON.stringify({ command })
    82→    });
    83→  };
    84→
    85→  return (
    86→    <div className="app">
    87→      <header>
    88→        <h1>Voice-Controlled Claude Code</h1>
    89→        <div className="header-actions">
    90→          <span className={`connection-status ${wsConnected ? 'connected' : 'disconnected'}`}>
    91→            {wsConnected ? '● Connected' : '○ Disconnected'}
    92→          </span>
    93→          <button onClick={createSession}>+ New Session</button>
    94→        </div>
    95→      </header>
    96→
    97→      <main>
    98→        <div className="sessions-panel">
    99→          <h2>Sessions</h2>
   100→          {sessions.length === 0 ? (
   101→            <div className="empty-sessions">No active sessions</div>
   102→          ) : (
   103→            sessions.map(session => (
   104→              <div
   105→                key={session.id}
   106→                className={`session-card ${selectedSession?.id === session.id ? 'active' : ''}`}
   107→                onClick={() => {
   108→                  setSelectedSession(session);
   109→                  setOutput([]);
   110→                }}
   111→              >
   112→                <h3>{session.name}</h3>
   113→                <span className={`status status-${session.status}`}>{session.status}</span>
   114→                <span className="commands">{session.commandsExecuted} commands</span>
   115→                <button
   116→                  className="terminate-btn"
   117→                  onClick={(e) => { e.stopPropagation(); terminateSession(session.id); }}
   118→                >
   119→                  Stop
   120→                </button>
   121→              </div>
   122→            ))
   123→          )}
   124→        </div>
   125→
   126→        <div className="session-panel">
   127→          {selectedSession ? (
   128→            <>
   129→              <div className="session-header">
   130→                <h2>{selectedSession.name}</h2>
   131→                <span className={`status status-${selectedSession.status}`}>
   132→                  {selectedSession.status}
   133→                </span>
   134→              </div>
   135→
   136→              <div className="command-bar">
   137→                <input
   138→                  type="text"
   139→                  placeholder="Enter command..."
   140→                  onKeyPress={(e) => {
   141→                    if (e.key === 'Enter') {
   142→                      sendCommand((e.target as HTMLInputElement).value);
   143→                      (e.target as HTMLInputElement).value = '';
   144→                    }
   145→                  }}
   146→                />
   147→                <button className="voice-btn">Voice</button>
   148→              </div>
   149→
   150→              <div className="output">
   151→                {output.length === 0 ? (
   152→                  <div className="empty-output">Waiting for output...</div>
   153→                ) : (
   154→                  output.map((line, i) => (
   155→                    <div key={i} className="output-line">{line}</div>
   156→                  ))
   157→                )}
   158→              </div>
   159→            </>
   160→          ) : (
   161→            <div className="empty-state">Select a session to view</div>
   162→          )}
   163→        </div>
   164→      </main>
   165→    </div>
   166→  );
   167→}
   168→
   169→export default App;
