    28→        ...event,
    29→        receivedAt: new Date().toISOString(),
    30→        sessionId: process.env.CLAUDE_SESSION_ID || 'unknown'
    31→      }),
    32→      signal: AbortSignal.timeout(1000) // 1s timeout
    33→    }).catch(err => {
    34→      // Log but don't fail
    35→      console.error('Hook delivery failed:', err.message);
    36→    });
    37→
    38→    // Always allow
    39→    process.exit(0);
    40→  } catch (err) {
    41→    console.error('Hook error:', err);
